#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,k,a[MAXN],d[301];
int mx,f[MAXN][25][5];
bool win(int x,int y)
{
	return (x-y==1)||(x==1&&y==3);
}
signed main(void)
{
	n=read(),k=read();
	FOR(i,1,n)
	{
		char c;
		cin>>c;
		if(c=='H')a[i]=1;
		else if(c=='P')a[i]=2;
		else if(c=='S')a[i]=3;
	}
	FOR(i,1,n)
	{
		FOR(j,0,min(k,i))
		{
			FOR(k,1,3)
            {
				int d=f[i-1][j][k]+win(k,a[i]);
				int a1,a2,tmp=-llinf;
				if(j)
				{
					a1=f[i-1][j-1][k%3+1]+win(k%3+1,a[i]);
					a2=f[i-1][j-1][(k+1)%3+1]+win((k+1)%3+1,a[i]);
					tmp=max(a1,a2);
				}
				f[i][j][k]=max(d,tmp);
			}			
		}
	}

	FOR(i,0,k)mx=max(mx,f[n][i][1]);
	FOR(i,0,k)mx=max(mx,f[n][i][2]);
	FOR(i,0,k)mx=max(mx,f[n][i][3]);
	write(mx);
	return false;
}
